INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_615757','Їжак',NULL,'uk','ukraine_1991',NULL,NULL,'Співаник тернопільського туристичного клюбу "Кристал"',NULL,'Їжак маму попрохав, попрохав, попрохав,
Щоби новаком він став, гей, він став, гей!

Хоче мати однострій, однострій, однострій,
І їжацький славний рій, славний рій, гей!

Сухе листя притащить, притащить, притащить,
Вогник жваво запалить, запалить, гей!

А на стійці буде так, буде так, буде так,
Коли стане там їжак, там їжак, гей!

Всі злякаються ввійти, гей, ввійти, гей, ввійти,
Бо він має колючки, колючки, гей!

А на тереновій грі, гей, на грі, гей, на грі,
В кулю скрутиться тоді, гей, тоді, гей!

Щоб хтось тільки покотив, покотив, покотив,
Перший прийде до мети, до мети, гей!','[''pisni.org.ua'', ''cat:plastovi'', ''Пластові пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_615757'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_615757','Їжак','Їжак маму попрохав, попрохав, попрохав,
Щоби новаком він став, гей, він став, гей!

Хоче мати однострій, однострій, однострій,
І їжацький славний рій, славний рій, гей!

Сухе листя притащить, притащить, притащить,
Вогник жваво запалить, запалить, гей!

А на стійці буде так, буде так, буде так,
Коли стане там їжак, там їжак, гей!

Всі злякаються ввійти, гей, ввійти, гей, ввійти,
Бо він має колючки, колючки, гей!

А на тереновій грі, гей, на грі, гей, на грі,
В кулю скрутиться тоді, гей, тоді, гей!

Щоб хтось тільки покотив, покотив, покотив,
Перший прийде до мети, до мети, гей!');
