INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6159178','Козак уїзжає','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 12.08.1993 Касета 3',NULL,'Козак уїжджає,
Дівчина заплаче,
Ой, дівчина заплаче,
Ой, не кидай, козаче.

Ой, якби ж я знала,
Що ти кидать будеш,
Ой, то я б твоє личко,
Ой, лиш змалювала.

Личко змалювала,
Ще й позолотила,
Ой, ще й позолотила,
До стінки прибила.

До тієї стінки,
Що шити сідаю,
Ой, до тії кроваті,
Що спати лягаю.

Ой, чи шила, не шила,
Взяла постилила,
Ой, чи спала, не спала,
Ой, взяла поцілувала','[''pisni.org.ua'', ''cat:arkhiv-bozhychi'', ''Фольклорний архів анс. "Божичі"'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6159178'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6159178','Козак уїзжає','Козак уїжджає,
Дівчина заплаче,
Ой, дівчина заплаче,
Ой, не кидай, козаче.

Ой, якби ж я знала,
Що ти кидать будеш,
Ой, то я б твоє личко,
Ой, лиш змалювала.

Личко змалювала,
Ще й позолотила,
Ой, ще й позолотила,
До стінки прибила.

До тієї стінки,
Що шити сідаю,
Ой, до тії кроваті,
Що спати лягаю.

Ой, чи шила, не шила,
Взяла постилила,
Ой, чи спала, не спала,
Ой, взяла поцілувала');
