INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6159940','Бог народився у місті Вифлиємі','Українська народна пісня. Виконує: Остап Кіндрачук','uk','ukr_ssr_1919_1991',NULL,NULL,'Остап Кіндрачук','Цю колядку колядували повстанці на Різдво в середині 40-их в с.Котиківка Івано-Франківської обл. на постої у батька кобзаря Остапа Кіндрачука Юрія.','Бог народився у місті Вифлиємі
У стаєнці.
Йому радіють усі українці
На землі.

І ми тебе просим,
Ісусе рожденний, хоч в ярмі:
Зглянься над тими,
Що плачуть-ридають у тюрмі.

Тих пошли до неба,
Що життя віддали за народ,
І тих, що вмерли
У східній Україні на голод.

То кати червоні
Братів вигубили нам рідних,
Сорок міліонів чекають до бою
Помстити їх.

А Степан Бандера —
Він був ув''язнений, він верне,
Київ відбере від катів червоних
Раз на все.

І задзвонять дзвони, і затрублять труби
У слушний час.
Ми підем до бою,
Ісусе рожденний, спаси нас.','[''pisni.org.ua'', ''cat:christian'', ''cat:istorychni'', ''cat:kolyadky'', ''cat:povstanski'', ''Пісні на християнську тематику'', ''Історичні пісні'', ''Колядки'', ''Повстанські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6159940'), datetime('now')),datetime('now'));
