INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_616050','В Вифлеємі днесь Марія','Українська народна пісня. Виконує: Ван Гог, Хор Осанна','uk','ukraine_before_1917',NULL,NULL,'Колядки / Упор. Ярина Коваль.- Львів: Каменяр, 1990.',NULL,'В Вифлеємі днесь Марія Пречиста
Породила у вертепі нам Христа
Приспів:
Слава во вишних Богу,  |
Слава во вишних Богу,  | (2)
І мир всім на землі.   |
Ангел з неба пастирям ся являє
І веселу новину звіщає!...
Приспів.
Прибігають до вертепу пастирі
І з собою несуть дари в офірі.
Приспів.
І Дитятку кланяються в оборі,
До його ніг припадають в покорі.
Приспів.
А з востока за звіздою йдуть царі,
Три преславні прерозумні звіздарі.
Приспів.
Книжники їм і учені сказали,
Щоб Месію в Вифлеємі питали.
Приспів.
Йдуть царі, Христа знаходять в яскині,
Між бидляти, в бідних яслах на сіні.
Приспів.
Там в смиренню свій Му поклін віддали,
Пред ним злото, ливан, миро поклали.
Приспів.
Ми також Христу поклін свій віддаймо
І разом з небесним хором співаймо.
Приспів','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:christian'', ''Церковні пісні'', ''Пісні на християнську тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_616050'), datetime('now')),datetime('now'));
