INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_616246','Аркан','Музика: Руслана Слова: Олександр Ксенофонтов. Виконує: Руслана','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Приспів:
Гей! Гей!.. Гей! Гей!..
За весною літо!
За зірками вітер!
Заплету їх у вінок!
Будуть в мене квіти!

Кажуть, земля без крил,
А вона жива!
Кажуть, що гори - пил,
А вони співа!
Кажуть, шкодуй себе,
А я просто неба!
Тиша і спокій всім,
А мені не тре!

Заспів:
Можливо світ змінити!
Так, знаю! Гей! Гей!
Нам танок не зупинити цей!
Там, за обрієм, де зорі
Стали в коло! Гей! Гей!
Я запалю ціле небо
Цілий всесвіт полум''ям очей!

Приспів.

Кажуть, мільйони сонць,
А воно одне!
Кажуть, безмежна ніч,
А вона мине,
Кажуть, любов - це сон,
Не шукай даремно,
Кажуть, її нема,
Але все дарма!

Заспів.

Приспів.

Перегра:
Місяць за горою,
Хмари над водою.
За вітрами сонце,
Зорі за віконцем,
За весною літо,
За зірками вітер,
Заплету їх у вінок,
Будуть в мене квіти.

Кажуть, шкодуй себе,
Над горами ніч,
Кажуть, любов мине,
Ти її не клич,
Кажуть, забудь, але
Я прийду до тебе
Поза часи й вітри,
Наче зірка з неба.

Приспів.

За зірками...
Буде вітер...
Заплету їх у вінок,
Будуть квіти.
Я прийду до тебе.
Наче зірка з неба!','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_616246'), datetime('now')),datetime('now'));
