INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6165454','А я дівчинка маленька','Музика: Ігор Іванців Слова: Володимир Наконечний','uk','ukraine_1991',NULL,NULL,'http://ivantsiv.at.ua',NULL,'А я дівчинка маленька,
Голосок чарівний маю.
Ніжно люблю татка й неньку
І про них вам заспіваю.
Мама в мене, наче бджілка,
Всіх годує й доглядає,
А татусь, як із причілка,
Із дивана поглядає.

Приспів:
Гей! Гей! Дана, дана, дана!
Гей! Дан, дана, гей!
Гей! Гей! Дан, дан!
Гей! Дан, дана, гей!

А я мамі допоможу,
Приведу все до порядку,
Принесу з криниці воду,
Посаджу квітки на грядку.

Приспів.','[''pisni.org.ua'', ''cat:dytyachi'', ''Дитячі пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6165454'), datetime('now')),datetime('now'));
