INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6159195','Туга за тугою','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 12.08.1993 Касета 3',NULL,'Туга за тугою,
Нудьга за нудьгою,
Віддала мене мати
Заміж молодою.

Пусти мене, милий,
По воду до броду,
По воду до броду
Аж до мого роду.

І сам не піду я
Й тебе не пущу я,
Бо ти скажеш роду
Про нашу невзгоду.

Бодай же, мій милий,
Гадюка сичала,
Щоб я своїй неньці
Правду не сказала.

Нащо ж мене, мамо,
На світ народила?
Нащо ж мені долю
Гірку наділила?','[''pisni.org.ua'', ''cat:arkhiv-bozhychi'', ''Фольклорний архів анс. "Божичі"'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6159195'), datetime('now')),datetime('now'));
