INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6163399','Наші фабрики й заводи','Музика: Остап Кіндрачук Слова: невідомий. Виконує: Остап Кіндрачук','uk','ukraine_1991',NULL,NULL,'Остап Кіндрачук','Коломийка написана невідомим львів''янином перед Помаранчевою революцією.','Наші фабрики й заводи
Майже не працюють,
А славнії українці
По світу мандрують.

Їде Хима аж до Рима
Панам ноги мити,
Бо на рідній Україні
Немож заробити.

Їде Юра до Росії
Москву будувати —
Аби мав за що у Львові
Дітей годувати.

А Марійка у Мадриді
Вже живе з іспанцем,
Каже мужу: "Прости, Грицю,
Будь моїм коханцем!"

Роз''їхалися селяни
Бакси заробляти —
Поля неньки України
Нікому орати.

З нас деруть страшні податки
Лихії хазари,
Замість школи будувати
Будуєм базари.

Зруйнували Україну
Наші депутати:
І червоні комуняки
Й ніби демократи.

Вони разом з бандитами
Державу грабують —
Возять гроші в чужі банки
І вілли купують.

Розпродують Україну
Нишком від народу
Чужим купцям із півночі,
Заходу і сходу.

Придивіться, українці,
Візьміть владу в руки,
Не ждіть добра від гаранта —
Матимете муки.

Придивляйтесь на виборах
Кого вибирати,
Аби знов чотири роки
Лікті не кусати.','[''pisni.org.ua'', ''cat:kolomyyky'', ''cat:suspilno-politychni'', ''Коломийки'', ''Суспільно-політичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6163399'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6163399','Наші фабрики й заводи','Наші фабрики й заводи
