INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6160848','Пісня про Сірка Івана','Музика: Я. Радавецький Слова: О. Хеміцький. Виконує: Остап Кіндрачук','uk','ukraine_1991',NULL,NULL,'Остап Кіндрачук','Після важкої осади 15 000 військом яничарів на Різдво Січі, в результаті якої в нічному бою було знищено майже 12 000 яничар, а решта захоплено в полон, Іван Сірко вирішує помститись туркам і вирушає навесні у похід на Крим, де залишились окремі чатини війська османів. В результаті походу було знищено турків і їх поселення, а султан врятувався втечею на галері в Стамбул.','Не тумани з моря, не тумани
Місяць, сонце покривали.
Гей, гей, димом небо вкрило, димом небо —   |
У Криму міста палали.                       | (2)

У Стамбулі турки, у Стамбулі
На схід сонця поглядали.
Гей, гей, чом вістей немає, вістей          |
з Криму? — |
Моря Чорного питали.                        | (2)

Гей, вістей не було та й не буде
Ані з вечера ні зрання.
Гей, гей, лягли яничари, полягали           |
Спати у Сірка Івана.                        | (2)

Не забудуть турки, не забудуть,
Як з Сірком бенкетували.
Гей, гей, з вина червоного, з червоного     |
Буйні голови поклали.                       | (2)

Десь заплаче мати, стара мати
За синами рано-вранці.
Гей, гей, будуть вить над ними, будуть вити |
Вовки сірі сіроманці.                       | (2)

Не тумани з моря, не тумани
Місяць, сонце покривали.
Гей, гей, димом небо вкрило, димом небо —   |
