INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6164271','Як поїхав та й той Лебеденко','Музика: Олексій Керекеша Слова: Тарас Шевченко. Виконує: Олексій Керекеша','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Як поїхав та й той Лебеденко
Та й в млин за мукою,
Як зустріли того Лебеденка
Та три гайдамаки.

Здоров, здоров, та ти, Лебеденку,
Та здоров, сину вражий.
Як ми з тобой та ти, Лебеденку,
Та пили та гуляли.

Ой, пили ж ми, пили і гуляли,
Одну совість мали,
Ой, веди ж, веди та ти, Лебеденку,
Та коня вороного.

Не поведу, ви сини вражі,
Хоч сам я загину,
Взяли вони того Лебеденка
Та на три списи вгору.

Прилетіла к тому Лебеденку
Та сивая зозуля,
Та й принесла ж тому Лебеденку,
Та й водиці напиться.

Ой, не хочу ж, сива зозуленько,
Та ні пити, ні їсти,
Донеси ж ти старій Лебедисі
Та жалібнії вісти.

Ой, прилетіла сива зозуленька
Та й сіла на стрісі,
Як вибігала стара Лебедиха
Та й рученьки в тісті.

Ой, прилетіла сива зозуленька
Та й стала кувати,
Як побігала стара Лебедиха
До сусідок питати.

Ой, сусідочки - сиві голубочки,
Щось за сон приснився:
Ой, бачиться мій син Лебеденко |
Та й в сю ніч оженився.        | (2)','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6164271'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6164271','Як поїхав та й той Лебеденко','Як поїхав та й той Лебеденко
Та й в млин за мукою,
