INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6168042','Щасливого Різдва','Музика: Богдан Кучер Слова: Богдан Кучер. Виконує: Іван Попович, Богдан Кучер','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'А я несу із далечі
Запалену свічу
Від Божої від Матері
Різдво і Коляду.
Несу молитву й Дідуха,
Дванадцять пісних страв
І Вефлеємську зіроньку,
Щоб Рік колядував.

Приспів:
Щасливого Різдва!          |
Щасливого Різдва!          |
Щасливого Нового Року!     |
Від дня народження Христа  |
До дня народження Христа   |
Хай буде доля нам нівроку! | (2)

А морозець не бавиться
І ген вертеп іде.
Я вірю, що не збавиться
Моє Різдво Святе.
Я вірю, все поправиться,
Бо від Різдва Христа
Усі ми починаємся,
Як з чистого листа.
І, звісно, щось минається
Та істина жива:
Мені Христос рожджається
Та Ірода нема.
І ми ще лан дооремо,
Засієм майбуття,
Поміж хрестами й зорями
Смачна буде кутя!

Приспів.','[''pisni.org.ua'', ''cat:kolyadky'', ''cat:new-year'', ''cat:shchedrivky'', ''cat:suchasni-pisni-rizdvo'', ''Колядки'', ''Пісні про Новий Рік'', ''Щедрівки'', ''Сучасні пісні про Різдвяні свята'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6168042'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6168042','Щасливого Різдва','А я несу із далечі
Запалену свічу
Від Божої від Матері
Різдво і Коляду.
Несу молитву й Дідуха,
Дванадцять пісних страв
І Вефлеємську зіроньку,
Щоб Рік колядував.

Приспів:
Щасливого Різдва!          |
Щасливого Різдва!          |
Щасливого Нового Року!     |
Від дня народження Христа  |
До дня народження Христа   |
Хай буде доля нам нівроку! | (2)

А морозець не бавиться
І ген вертеп іде.
Я вірю, що не збавиться
Моє Різдво Святе.
Я вірю, все поправиться,
Бо від Різдва Христа
Усі ми починаємся,
Як з чистого листа.
І, звісно, щось минається
Та істина жива:
Мені Христос рожджається
Та Ірода нема.
І ми ще лан дооремо,
Засієм майбуття,
Поміж хрестами й зорями
Смачна буде кутя!

Приспів.');
