INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6165644','В новорічну ніч','Музика: Ірина Білик Слова: Ірина Білик. Виконує: Ірина Білик','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'По колу, по колу годинники знову
Чарівні секунди несуть,
Я знаю, що диво не зможе ніколи
Планету в цю мить обминуть.

Приспів:
В новорічну ніч все таке казкове!
В новорічну ніч кришталевий дзвін!
В новорічну ніч я кохаю знову!
В новорічну ніч ти вже не один!

Смачні подарунки дарують ялинки,
Радіють малі дітлахи,
Візьмемось за руки,
Сміються ж так дзвінко
У небі зірки і птахи!

Приспів.

В новорічну ніч! | (4)

