INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6169656','Ой ну, люлі, люлі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986',NULL,'Ой ну, люлі, люлі,
Налетіли гулі
Та сіли на люлі,
Сіли на воротях
В червоних чоботях.
Ворітечка скрип-скрип,
Мале дитя спить, спить.
Цитьте, гулі, не гудіть,
Мале дитя не будіть,
Бо дитятко маленьке,
Воно спати раденьке.
А дитятко буде спать
Та не буде плакать.
А, а, а!','[''pisni.org.ua'', ''cat:kolyskovi'', ''Колискові'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6169656'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6169656','Ой ну, люлі, люлі','Ой ну, люлі, люлі,
