INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6170555','Спасе і Христе','Слова: о. Й. Кишакевич','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Спасе і Христе, перед Тобою
Ангели Божі дрожать жахом.
Як окружають Тебе дугою,
Співають хвали, слави псалом.
Тебе у віки лиш оглядати              |
Вони бажають з усіх сил,              |
Тобі "Осанна!" у честь співати        |
І окружати дугою крил.                | (2)

Ми, Спасе Христе, враз з ангелами
Перед Тобою днесь стоїмо:
Як привітаєм Тебе між нами
І як належну честь віддамо?
Викинем з серця все, що лукаве,       |
З душі стрясемо гріховний пил         |
І заспіваєм Тобі піснь слави,         |
Піснь на подобу ангельських сил.      | (2)

Тобі одному лиш безнастанна
Піснь слави, чести від рода в род,
Ангельська пісня "Свят, свят, осанна!
Господь сил вишних, Бог Саваот!"
"Свят, свят, осанна!" най не вмовкає, |
Пісня в день щастя, чи в час скорбот, |
Нехай враз з нами весь світ співає:   |
"Господь сил вишних, Бог Саваот!"     | (2)','[''pisni.org.ua'', ''cat:christ'', ''Пісні до Ісуса Христа'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6170555'), datetime('now')),datetime('now'));
