INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6170144','Зима','Музика: Леся Горова Слова: Леся Горова. Виконує: Леся Горова, Вікторія Федун','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Вікторія Федун.','У мої долоні впала
Білосніжна казкова мить,
Щоб сніжинка не розтала
Я пустила нехай летить.

Приспів:
Це зима, це зима,        |
Це казкова зима,         |
Доторкнулася мрій моїх,  |
Все навколо чарує,       |
Чарує вона,              |
Перетворює в білий сніг. | (2)

А мої рум''яні щоки
Вже щипає морозець,
Рік іде услід за роком
І початком стає кінець.

Приспів.

Перетворює в білий сніг!..

У моїй душі співає
Вже колядками зима,
Душу святом зігріває,
Хоч вона і крижана.

Приспів.

Перетворює в білий сніг!','[''pisni.org.ua'', ''cat:krasa-pryrody'', ''Пісні про красу природи'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6170144'), datetime('now')),datetime('now'));
