INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6167899','Бабусина колисанка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'http://www.malecha.org.ua/',NULL,'Люлі-люлі...
