Як була маленька.','[''pisni.org.ua'', ''cat:dytyachi'', ''cat:kolyskovi'', ''cat:narodni'', ''Дитячі пісні'', ''Колискові'', ''Народні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6167899'), datetime('now')),datetime('now'));
