INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6170570','Бог ся нам об''явив','Слова: о. І. Дуцько','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Бог ся нам об''явив в трьох святих Особах,
Як Христос ся хрестив на Йорданських водах,
Як Христос ся хрестив на Йорданських водах.

Із небесних вижин Бог Отець голосить:
То є мій милий Син, що нам мир приносить!
То є мій милий Син, що нам мир приносить!

А горою Бог Дух голубом злітає,
