INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6172093','Маріє, Діво Пресвята','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Господь - моя пісня. Збірник релігійних пісень. Упор. Т.Ференц, І.Мельник, О.Костецька. Львів: "Свічадо", 2005.',NULL,'Маріє, Діво Пресвята,
Ти дівством краща всіх лелій,
Одні лиш гідні небеса
Тобі віддать поклін, Святій!

Приспів: (2)
Позволь і нам славить Тебе,
Хоч наше серце не святе,
Щоб піснь святу Тобі
Співали на землі.

Маріє Діво Пресвята,
Як Ти для нас є дорога —
Наше життя і наш Ти рай,
Вітай нам, Маріє, вітай.

Приспів.

Маріє, Діво Пресвята,
Надіє нашого життя,
До Тебе йдемо в кожний час,
Рятуй від злого завжди нас.

Приспів.','[''pisni.org.ua'', ''cat:cerkovni'', ''cat:do-bohorodyci'', ''Церковні пісні'', ''Пісні до Богородиці'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6172093'), datetime('now')),datetime('now'));
