INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6174178','А чи єст, чи нема?','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.43','Виконує: сім''я Барни, с.Кам''янка','А чи єст, чи нема пан господар дома?
Дай, Боже!
А дай же му, Боже, щастя і здоровля,
Дай, Боже!
А што він там робит? Там пшеничку сіє,
Дай, Боже!
А дай же му, Боже, щастя і здоровля,
Дай, Боже!
А чи єст, чи нема господині дома?
Дай, Боже!
А дай же їй, Боже, щастя і здоровля,
Дай, Боже!
А што она робит? Там пампушки смажит.
Дай, Боже!
А дай же їй, Боже, щастя і здоровля,
Дай, Боже!
А ход же ми до ней, заколядуєм.
Дай, Боже!
А дай же їй, Боже, щастя і здоровля,
Дай, Боже!
А даст нам коляду, пампушка додому.
Дай, Боже!
А дай же їй, Боже, щастя і здоровля,
Дай, Боже!
Ой, добрі ти, добрі в тій теплій хижонці сидіти,
А нас ту ноженьки болят від зимна юж ходити.
А дай їм, Боже, всім нашим газдонькам,
Дай, Боже!
А дай, Боже, їм  щастя і дай здоровленька,
Дай, Боже!','[''pisni.org.ua'', ''cat:lemkivski'', ''Лемківські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6174178'), datetime('now')),datetime('now'));
