INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6171797','Плач Ярославни','Музика: Ігор Білозір Слова: Богдан Стельмах','uk','ukraine_1991',NULL,NULL,'Стельмах Б. М. Світлиця пісень і спогадів.- Львів: Сполом, 2001.',NULL,'Рано в Путивлі та й на заборолі
Плаче княжа жона;
То Ярославна просить вітра в полі -
В''ється, б''ється луна:
"Вітре, одвій од полків наших
Половецьку стрілу,
Щоб моя радість порохом не впала
На суху ковилу!..

Приспів:
Я зегзицею стану —
Закричу, заячу,
Над Каялою рано
По воді пролечу -
Князю Ігорю рану
Замолю, зашепчу..."

Рано в Путивлі - ой, далеко чути -
Плаче княжа жона;
То Ярославна у Дніпра-Славути
Помочі виклина:
"Дніпре, не кинь ти мого лада
В половецькій біді,
Щоб я до нього сліз не посилала
По твоїй по воді!..

Приспів.

Рано в Путивлі жалем серце крає -
Плаче княжа жона;
То Ярославна сонця докликає,
Що над морем зрина:
"Сонце, спинись, не пали дуже,
Не висушуй степів,
Щоб у неволі, в половецькім полі
Спраги князь не терпів!..

Приспів.','[''pisni.org.ua'', ''cat:istorychni'', ''Історичні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6171797'), datetime('now')),datetime('now'));
