INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6176271','Перший дзвоник','Музика: Михайло Герц Слова: Михайло Шушкевич','uk','ukraine_1991',NULL,NULL,NULL,'є фонограма','Перший дзвоник продзвенів
В радісну хвилину.
Мов пташинний ніжний спів
В синь небес полинув.

Приспів:
Перший дзвоник, перший дзвоник
Ти дзвени в блакитну рань.
Перший дзвоник, перший дзвоник
Клич дітей в країну знань.
Першу вчительку свою,
Привітали діти.
Посмішками клас розцвів,
Мов осінні квіти.

Із букетами у клас
Йдуть щасливі діти.
Бо прийшов навчання час,
Як же не радіти.

Перше вересня-день знань,
Золотіють квіти.
День надій і сподівань,
З святом любі діти','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6176271'), datetime('now')),datetime('now'));
