INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6173570','Прощавай, рідна школо','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Пролунав дзвінок останній,
Соловейком віддзвенів,
Ми йдемо в дорогу дальню
На очах учителів,
На душі бринить тривога,
Занімів порожній клас,
То дитинство босоноге
Проводжає тихо нас...

Приспів:
Прощавай, рідна школо,
Тільки знай, сумуватиму я,
Пам''ятай ті слова золоті:
Ти для нас - найдорожча в житті!

Упадуть на землю роси,
Зійде сонце на поріг,
Дітвора дзвінкоголоса
Тихо стане на поріг
І здійсняться сни пророчі
На стежині будніх днів
І теплом засяють очі
Наших рідних вчителів.

Приспів.

Ти для нас - найдорожча в житті!','[''pisni.org.ua'', ''cat:shkilni'', ''Пісні про школу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6173570'), datetime('now')),datetime('now'));
