INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_617899','Благослови, душе моя, Господа','Музика: Кирило Стеценко Слова: Псалом 103 (Давидів). Виконує: Євшан','uk','ukraine_1991',NULL,'2002','Шалена Зірка','Євшан, 2002 Почуй молитву мою, Господи. Повний текст Псалому 103 - варіанти: http://murtonsys.com/bibledatabase/htmlc/ukrainian/19_103.htm http://bible.gospelcom.net/passage/?book_id=23&chapter=103&version=27 Порядок головного богослужіння зі Сповіддю і Господньою Вечерею (для українських євангельских громад Авґсбурзького Віросповідання): http://bohm.narod.ru/lityrgy/lityrgy1.html Божественна Літургія Української Лютеранської Церкви: www.angelfire.com/ca4/ saintsophiaseminary/liturgyukrainian.html','Благослови, душе моя, Господа,
Благословенний єси Господи.

Благослови, душе моя, Господа,
І вся істота моя Ім''я Святеє Його.

Благослови, душе моя, Господа,
І не забувай всіх добродійств Його.

Благослови, душе моя, Господа,
Благословенний єси Господи','[''pisni.org.ua'', ''cat:cerkovni'', ''Церковні пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_617899'), datetime('now')),datetime('now'));
