INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6179746','Дев''яте Травня','Музика: Микола Дайнега Слова: Тамара Острополець. Виконує: Марта Шпак','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я - онука солдата, що вернувся з війни,
Маю змогу кохати і радіти весні.
Та у день перемоги в дідусевих очах
Помічаю тривогу, помічаю печаль.

Приспів:
Дев''яте Травня - незабутнє свято!
Палають квіти в селах і містах.
Згадаймо всі, хто прадіда, хто брата,
Що полягли на фронтових шляхах.
Дев''яте Травня - свято Перемоги!
Воно не відійде у небуття,
Якою б далі не була дорога,
Спасибі вам, солдати, за життя!

Був мій батько хлопчиськом босоногим малим,
Пам''ятаю, як низько, крили землю дими,
Як гриміли гармати і принишкло село,
Як безвусі солдати йшли у бій за Дніпро!

Приспів.

Все минуло, скінчилось, перемога була!
Я на світ народилась і у мирі зросла,
І вклоняюся низько всім солдатам війни,
Тим, що нашу вітчизну захистити змогли!

Приспів.

За життя! Спасибі Вам за життя!','[''pisni.org.ua'', ''cat:suspilno-politychni'', ''cat:viyskovi'', ''Суспільно-політичні пісні'', ''Пісні на військову тематику'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6179746'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6179746','Дев''яте Травня','Я - онука солдата, що вернувся з війни,
Маю змогу кохати і радіти весні.
Та у день перемоги в дідусевих очах
Помічаю тривогу, помічаю печаль.

Приспів:
Дев''яте Травня - незабутнє свято!
Палають квіти в селах і містах.
Згадаймо всі, хто прадіда, хто брата,
Що полягли на фронтових шляхах.
Дев''яте Травня - свято Перемоги!
Воно не відійде у небуття,
Якою б далі не була дорога,
Спасибі вам, солдати, за життя!

Був мій батько хлопчиськом босоногим малим,
Пам''ятаю, як низько, крили землю дими,
Як гриміли гармати і принишкло село,
Як безвусі солдати йшли у бій за Дніпро!

Приспів.

Все минуло, скінчилось, перемога була!
Я на світ народилась і у мирі зросла,
І вклоняюся низько всім солдатам війни,
Тим, що нашу вітчизну захистити змогли!

Приспів.

За життя! Спасибі Вам за життя!');
