INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6182879','Весільна осінь','Музика: Олександр Злотник Слова: Володимир Мельников. Виконує: Володимир Мельников','uk','ukraine_1991',NULL,'2010','Авторське подання','У такому варіанті ця пісня пролунала 12.09.2010 на весіллі Сергія і Анжели Саєнків: Ми вітаємо вас! Йде по Києву осінь весільна! Наче Ангел з небес, наречена Анжела у нас. Вже дружина вона, а з коханим – свята і всесильна... "Тож купайтесь в любові", – звертаються гості до вас. Дорогі молодята! Наші рідні, Сергій і Анжела! Ми бажаємо вам – море Квітів, Любові, Тепла! В океані кохання – хай летить ваших мрій каравела. У подружнім житті ви тепер два вітрила - крила. Від кохання батьків у родинах з''являються діти. Виростають вони, "Вже Серьожа – до хмар дістає"... Як радіють батьки... Скоро будуть онукам радіти! Бо і "хата" вже є, і кохання з наснагою є. Дорогі молодята! Наші рідні, Сергій і Анжела! Ми бажаємо вам – море Квітів, Любові, Тепла! В океані кохання – хай летить ваших мрій каравела. У подружнім житті ви тепер два вітрила - крила. ЩИРІ ВІТАННЯ УСІМ МОЛОДЯТАМ УКРАЇНИ!','Ми вітаємо вас! І вітає вас осінь весільна!
Наче Ангел з небес, наречена сьогодні у нас.
Вже дружина вона, а з коханим - свята і всесильна...
"Тож купайтесь в любові", - звертаються гості до вас.

Приспів:
Дорогі молодята! Ви ще зовсім маленька родина!
Ми бажаємо вам - море Квітів, Любові, Тепла!
В океані кохання - хай летить ваших мрій бригантина.
У подружнім житті  ви тепер два вітрила - крила.

Від кохання батьків у родинах з''являються діти.
Виростають вони і весілля їх день настає...
Як радіють батьки... Скоро будуть онукам радіти!
Бо для цього все є. Для кохання і щастя - все є.

Приспів','[''pisni.org.ua'', ''cat:vesilni'', ''cat:zahalni-cinnosti'', ''Весільні пісні'', ''Пісні про загальнолюдські цінності'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6182879'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6182879','Весільна осінь','Ми вітаємо вас! І вітає вас осінь весільна!
Наче Ангел з небес, наречена сьогодні у нас.
Вже дружина вона, а з коханим - свята і всесильна...
"Тож купайтесь в любові", - звертаються гості до вас.

Приспів:
Дорогі молодята! Ви ще зовсім маленька родина!
Ми бажаємо вам - море Квітів, Любові, Тепла!
В океані кохання - хай летить ваших мрій бригантина.
У подружнім житті  ви тепер два вітрила - крила.

Від кохання батьків у родинах з''являються діти.
Виростають вони і весілля їх день настає...
Як радіють батьки... Скоро будуть онукам радіти!
Бо для цього все є. Для кохання і щастя - все є.

Приспів');
