INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6183195','Про кума','Музика: Ігор Петренко. Виконує: Ігор Петренко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Картопля смажена,
Сало та цибуля,
О-хо-хо-хо,
Жіночка відряджена
І в кишенях дуля,
О-хо-хо-хо,
Слухавку тримаю,
Кума набираю,
О-хо-хо-хо.

Куме, маєм свято,
Не беріть багато!
Куме, маєм свято,
Не беріть багато!
О-хо-хо-хо!

Де одна - там сварка,
А де дві - там бійка,
Тритю мусим пити,
П''ята - будем жити!
Кум брови зсупив,
Капелюха здвинув:
Чверу ти поцупив,
Що ж ми за родина?

Ксьонз бере десяту,
А держава - третю,
Ти ж пробачиш, брате,
Що я вкрав четверту.
Шоста, сьома, восьма
Там, де і десята,
Як так будем жити,
То не буде свята!

Картопля смажена,
Сало та цибуля,
І в кишенях дуля...

Як так будем жити,
То не буде свята!','[''pisni.org.ua'', ''cat:bardivski'', ''Бардівські пісні'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6183195'), datetime('now')),datetime('now'));
