INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6183776','Пісня Литві','Музика: Олег Покальчук Слова: Олег Покальчук. Виконує: Олег Покальчук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'На вежі Гедиміноса
І на Високім Замку
Час піднімає прапори
Вітрилами надій,
І їхні лісові брати,
І наші партизани
Тепер спокійно спатимуть
У славі січовій!

Приспів:
Вперед, Литво!
Вперед! Вперед!
Пробач, що ми не поруч!
Нам теж не місце у музеї
Воскових фігур!
На спільному шляху вперед,
Завжди вперед і вгору!
Хай помагають нам святі
І Вітовтас, і Юр!

Майбутнє наших націй знов
Поставлено на карту,
Чи виграв, чи програв,
Та честь ніхто не відбере,
Ми теж чекаєм виходу
З радянського плацкарту,
Бо поїзд сунеться назад,
А час іде вперед.

Приспів.

Вперед, Литво!
Вперед! Вперед!
Пробач, що ми не поруч!
Нам теж не місце у музеї
Воскових фігур!
Шлях до свободи лиш один -
Завжди вперед і вгору!
Кремлівський мур також паде,
Як і Берлінський мур!','[''pisni.org.ua'', ''cat:druzhba'', ''Пісні про дружбу'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6183776'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6183776','Пісня Литві','На вежі Гедиміноса
І на Високім Замку
Час піднімає прапори
Вітрилами надій,
І їхні лісові брати,
І наші партизани
Тепер спокійно спатимуть
У славі січовій!

Приспів:
Вперед, Литво!
Вперед! Вперед!
Пробач, що ми не поруч!
Нам теж не місце у музеї
Воскових фігур!
На спільному шляху вперед,
Завжди вперед і вгору!
Хай помагають нам святі
І Вітовтас, і Юр!

Майбутнє наших націй знов
Поставлено на карту,
Чи виграв, чи програв,
Та честь ніхто не відбере,
Ми теж чекаєм виходу
З радянського плацкарту,
Бо поїзд сунеться назад,
А час іде вперед.

Приспів.

Вперед, Литво!
Вперед! Вперед!
Пробач, що ми не поруч!
Нам теж не місце у музеї
Воскових фігур!
Шлях до свободи лиш один -
Завжди вперед і вгору!
Кремлівський мур також паде,
Як і Берлінський мур!');
