INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6184093','Харків моя любов','Музика: В''ячеслав Корепанов Слова: Олекса Марченко. Виконує: Євгенія Костенко','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Зоринкою світла сльоза,
Упала в рясні в лісопарку.
Мене проведи на вокзал,
Бо я залишаю мій Харків.

Приспів:
Вечір у вікна постукав,
Спогад зоріє обом.
Харків для когось розлука,
Харків для мене любов.
Харків для когось розлука,
Харків для мене любов.

Хвилює прощання без слів,
Сміються троянди пахучі.
Зі мною ти мовчки присів,
Щоб слалась дорога співуча.

Приспів.

За обрій ідуть поїзди,
А дощ за вечірнім держпромом.
Розлука відступить завжди,
І я повернуся додому.

Приспів:
Вечір у вікна постукав,
Спогад зоріє обом.
Харків для когось розлука,
Харків для мене любов.
Харків для когось розлука,
Харків моя любов.
Харків моя любов.','[''pisni.org.ua'', ''cat:slobozhanski'', ''Пісні з слобожанщини'']',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6184093'), datetime('now')),datetime('now'));
